        System.out.print("Enter monthly salary : Rs. ");
        double monthly = sc.nextDouble();

        double yearly = monthly * 12;
        double tax = 0;

        if (yearly <= 250000) {
            tax = 0;
        } else if (yearly <= 500000) {
            tax = (yearly - 250000) * 0.05;
        } else if (yearly <= 1000000) {
            tax = 12500 + (yearly - 500000) * 0.20;
        } else {
            tax = 112500 + (yearly - 1000000) * 0.30;
        }

        System.out.println();
        System.out.println("Monthly Salary      : Rs. " + monthly);
        System.out.println("Yearly Salary       : Rs. " + yearly);
        System.out.println("Income Tax          : Rs. " + tax);
        System.out.println("Salary After Tax    : Rs. " + (yearly - tax));

        System.out.println();
