class program13 {

    static double volume(double l, double w, double h) {
        return l * w * h;
    }

    static double surfaceArea(double l, double w, double h) {
        return 2 * (l * w + w * h + l * h);
    }

    static double lateralArea(double l, double w, double h) {
        return 2 * h * (l + w);
    }

    public static void main(String[] args) {

        System.out.println("---");
