class Box {

    double length;
    double width;
    double height;

    Box(double length, double width, double height) {
        this.length = length;
        this.width  = width;
        this.height = height;
    }

    void display() {
        System.out.println("Length : " + this.length);
        System.out.println("Width  : " + this.width);
        System.out.println("Height : " + this.height);
    }

    Box getThis() {
        return this;
    }

    void compare(Box b) {
        if (this.length == b.length && this.width == b.width && this.height == b.height)
            System.out.println("Both boxes are identical.");
        else
            System.out.println("Boxes are different.");
    }
}

